// Medici radiologi (imagistică / RMN) — relevanți pentru pagina RMN.
export const radiologists: AffideaDoctor[] = affideaDoctors.filter((d) =>
  d.specialties.some((s) => /Radiolog/i.test(s)),
);

export function doctorsAtCenter(centerSlug: string): AffideaDoctor[] {
  return affideaDoctors.filter((d) => d.centers.some((c) => c.slug === centerSlug));
}

export function radiologistsInCity(cityTitle: string): AffideaDoctor[] {
  return radiologists.filter((d) => d.centers.some((c) => c.city === cityTitle));
}
